297→{% javascript %}
298→  class StickyHeader extends HTMLElement {
299→    constructor() {
300→      super();
301→    }
302→
303→    connectedCallback() {
304→      this.header = document.querySelector('.section-header');
305→      this.headerIsAlwaysSticky = this.getAttribute('data-sticky-type') === 'always' || this.getAttribute('data-sticky-type') === 'reduce-logo-size';
306→      this.headerBounds = {};
307→
308→      this.setHeaderHeight();
309→
310→      window.matchMedia('(max-width: 990px)').addEventListener('change', this.setHeaderHeight.bind(this));
311→
312→      if (this.headerIsAlwaysSticky) {
313→        this.header.classList.add('shopify-section-header-sticky');
314→      };
315→
316→      this.currentScrollTop = 0;
317→      this.preventReveal = false;
318→      this.predictiveSearch = this.querySelector('predictive-search');
319→
320→      this.onScrollHandler = this.onScroll.bind(this);
321→      this.hideHeaderOnScrollUp = () => this.preventReveal = true;
322→
323→      this.addEventListener('preventHeaderReveal', this.hideHeaderOnScrollUp);
324→      window.addEventListener('scroll', this.onScrollHandler, false);
325→
326→      this.createObserver();
327→    }
328→
329→    setHeaderHeight() {
330→      document.documentElement.style.setProperty('--header-height', `${this.header.offsetHeight}px`);
331→    }
332→
333→    disconnectedCallback() {
334→      this.removeEventListener('preventHeaderReveal', this.hideHeaderOnScrollUp);
335→      window.removeEventListener('scroll', this.onScrollHandler);
336→    }
337→
338→    createObserver() {
339→      let observer = new IntersectionObserver((entries, observer) => {
340→        this.headerBounds = entries[0].intersectionRect;
341→        observer.disconnect();
342→      });
343→
344→      observer.observe(this.header);
345→    }
346→
347→    onScroll() {
348→      const scrollTop = window.pageYOffset || document.documentElement.scrollTop;
349→
350→      if (this.predictiveSearch && this.predictiveSearch.isOpen) return;
351→
352→      if (scrollTop > this.currentScrollTop && scrollTop > this.headerBounds.bottom) {
353→        this.header.classList.add('scrolled-past-header');
354→        if (this.preventHide) return;
355→        requestAnimationFrame(this.hide.bind(this));
356→      } else if (scrollTop < this.currentScrollTop && scrollTop > this.headerBounds.bottom) {
357→        this.header.classList.add('scrolled-past-header');
358→        if (!this.preventReveal) {
359→          requestAnimationFrame(this.reveal.bind(this));
360→        } else {
361→          window.clearTimeout(this.isScrolling);
362→
363→          this.isScrolling = setTimeout(() => {
364→            this.preventReveal = false;
365→          }, 66);
366→
367→          requestAnimationFrame(this.hide.bind(this));
368→        }
369→      } else if (scrollTop <= this.headerBounds.top) {
370→        this.header.classList.remove('scrolled-past-header');
371→        requestAnimationFrame(this.reset.bind(this));
372→      }
373→
374→      this.currentScrollTop = scrollTop;
375→    }
376→
377→    hide() {
378→      if (this.headerIsAlwaysSticky) return;
379→      this.header.classList.add('shopify-section-header-hidden', 'shopify-section-header-sticky');
380→      this.closeMenuDisclosure();
381→      this.closeSearchModal();
382→    }
383→
384→    reveal() {
385→      if (this.headerIsAlwaysSticky) return;
386→      this.header.classList.add('shopify-section-header-sticky', 'animate');
387→      this.header.classList.remove('shopify-section-header-hidden');
388→    }
389→
390→    reset() {
391→      if (this.headerIsAlwaysSticky) return;
392→      this.header.classList.remove('shopify-section-header-hidden', 'shopify-section-header-sticky', 'animate');
393→    }
394→
395→    closeMenuDisclosure() {
396→      this.disclosures = this.disclosures || this.header.querySelectorAll('header-menu');
397→      this.disclosures.forEach(disclosure => disclosure.close());
398→    }
399→
400→    closeSearchModal() {
401→      this.searchModal = this.searchModal || this.header.querySelector('details-modal');
402→      this.searchModal.close(false);
403→    }
404→  }
405→
406→  customElements.define('sticky-header', StickyHeader);
407→{% endjavascript %}
